void permute(int a[],int b[],int n)

{

	int t[MAXN];

	for(R int i=1;i<=n;++i)

	  t[i]=a[i];

	for(R int i=1;i<=n;++i)

	  a[i]=t[b[i]];

}



void fpow(int a[],LL y,int n)

{

	while(y)

	{

		if(y&1)permute(d,a,n);

		permute(a,a,n),y>>=1;

	}

}





